module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

reg [3:0] shift_reg;
reg [1:0] count;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        shift_reg <= 4'b0;
        count <= 2'b0;
    end
    else begin
        if (count == 2'b11) begin
            shift_reg <= d;
            count <= 2'b0;
        end
        else begin
            shift_reg <= {shift_reg[2:0], 1'b0};
            count <= count + 1'b1;
        end
    end
end

assign valid_out = (count == 2'b11) ? 1'b1 : 1'b0;
assign dout = (count == 2'b11) ? shift_reg[3] : 1'b0;

endmodule
